export type DocumentStatus = 
  | 'imported'        // Étape 1 : Importé (à traiter)
  | 'transcribing'    // Étape 2 : En transcription
  | 'transcribed'     // Étape 2 : Transcription achevée (à relire)
  | 'reviewing'       // Étape 3 : En relecture
  | 'reviewed'        // Étape 3 : Relecture achevée (à tagger)
  | 'tagging'         // Étape 4 : En tagging
  | 'tagged'          // Étape 4 : Tagging achevé (à éditer)
  | 'editing'         // Étape 5 : En édition
  | 'edited';         // Étape 5 : Édition achevée (finalisé)

export type WorkflowStep = 1 | 2 | 3 | 4 | 5;

export interface Document {
  id: string;
  title: string;
  type: 'Transcription' | 'Audio' | 'Édition' | 'Vidéo' | 'Image';
  source: string;
  status: DocumentStatus;
  workflow_step: WorkflowStep;
  progress: number;
  assigned_to: string;
  tags: string[];
  file_url?: string;
  content?: string;
  created_at: string;
  updated_at: string;
  user_id: string;
  metadata?: any;
  categories?: {
    volume?: string;
    year?: string;
    location?: string;
    person?: string;
  };
}

export interface DocumentFormData {
  title: string;
  type: string;
  source: string;
  status: DocumentStatus;
  workflow_step?: WorkflowStep;
  progress: number;
  assigned_to: string;
  tags?: string[];
  file_url?: string;
  content?: string;
}

// ✅ EXPORTER COMME VALEURS (pas juste types)
export const STATUS_TO_STEP: Record<DocumentStatus, WorkflowStep> = {
  'imported': 1,
  'transcribing': 2,
  'transcribed': 2,
  'reviewing': 3,
  'reviewed': 3,
  'tagging': 4,
  'tagged': 4,
  'editing': 5,
  'edited': 5,
};

export const STATUS_TO_PROGRESS: Record<DocumentStatus, number> = {
  'imported': 0,
  'transcribing': 20,
  'transcribed': 40,
  'reviewing': 40,
  'reviewed': 60,
  'tagging': 60,
  'tagged': 80,
  'editing': 80,
  'edited': 100,
};

export const STATUS_LABELS: Record<DocumentStatus, string> = {
  'imported': 'À traiter',
  'transcribing': 'Transcription en cours',
  'transcribed': 'À relire',
  'reviewing': 'Relecture en cours',
  'reviewed': 'À tagger',
  'tagging': 'Tagging en cours',
  'tagged': 'À éditer',
  'editing': 'Édition en cours',
  'edited': 'Édité',
};

export {};
